  const [cardColors, setCardColors] = useState({});

  const extractCardColor = (id, imgEl) => {
    try {
      const canvas = document.createElement("canvas");
      canvas.width = 4; canvas.height = 60;
      const ctx = canvas.getContext("2d");
      // Sample the LEFT edge of the image — where it meets the text side
      ctx.drawImage(imgEl, 0, 0, 4, 60);
      const data = ctx.getImageData(0, 0, 4, 60).data;
      let r = 0, g = 0, b = 0, count = 0;
      for (let i = 0; i < data.length; i += 4) {
        r += data[i]; g += data[i+1]; b += data[i+2]; count++;
      }
      r = Math.round(r/count); g = Math.round(g/count); b = Math.round(b/count);
      const color = "rgb(" + r + "," + g + "," + b + ")";
      setCardColors(prev => ({ ...prev, [id]: color }));
    } catch(e) {}
  };

  const dotScrollRef = useRef(null);
